export const isNativeWindows = () => {
  if (typeof window === 'undefined') {
    return false
  }

  const hasNativeBridge = !!(
    window.webkit &&
    window.webkit.messageHandlers
  )

  const isIOSDevice = /iPad|iPhone|iPod/.test(window.navigator.userAgent) ||
    (window.navigator.platform === 'MacIntel' && window.navigator.maxTouchPoints > 1)

  return hasNativeBridge || isIOSDevice
}

export const sendMessageToIos = (action, params) => {
  if (isNativeWindows()) {
    window.webkit.messageHandlers.prey.postMessage({ action, params: params || {} })
  } else {
    console.log('[sendMessageToIos]', action, params || {})
  }
}
