import React from "react";
import { I18n } from "react-i18nify-lite";
import { Loading } from "../assets/Dialog";
import logomono from "../images/branding/prey-logo-monotono-alt.svg";
import { sendMessageToIos } from "./commons";

const initName = () => {
  sendMessageToIos("namedevice", { openPanelWeb: true });
  return "";
};

export default class Lock extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      data: {},
      exists: false,
      name: initName(),
      isLoading: false,
      nameError: "",
    };
  }

  errorsFor = (name) => {
    const errors = this.state.data[name];
    if (!errors) return;
    if (errors.length === 0) return;

    return (
      <div className="info info-error">
        {errors.map((o, i) => (
          <p key={i}>{o}</p>
        ))}
      </div>
    );
  }

  changeName = (ev) => {
    ev.preventDefault();
    this.setState({
      name: "",
    });
  };

  handleChangeName = (e) => {
    e.preventDefault();
    this.setState({
      name: document.getElementById("nametext").value,
    });
  };

  handleClickRename = (e) => {
    let newName = encodeURIComponent(document.getElementById("newName").value);
    sendMessageToIos("rename", { newName });
  };

  handleClickCancel = (ev) => {
    sendMessageToIos("index");
  };

  render() {
    return (
      <div className="rename fs-onboarding regular inverted rename-redesign">
        <div className="column">
          <div className="permissions-brand rename-brand">
            <img src={logomono} alt="Prey" className="permissions-brand-logo" />
          </div>
          <div className="sign-form login-panel login-card rename-card">
            <h4 className="heading">{I18n.t("rename.heading")}</h4>
            <p className="rename-copy">{I18n.t("rename.body")}</p>
            <form
              autoComplete="off"
              className="form form-session"
              acceptCharset="UTF-8"
            >
              <ul className="form vvv">
                <li>
                  <label className="rename-label" htmlFor="currentName">
                    {I18n.t("rename.current")}
                  </label>
                  <div className="rename-input rename-input-readonly" id="currentName">
                    <span className="rename-readonly-value">{this.state.name}</span>
                  </div>
                </li>
                <li>
                  <label className="rename-label" htmlFor="newName">{I18n.t("rename.write")}</label>
                  <input
                    className="rename-input"
                    id="newName"
                    name="newName"
                    placeholder=""
                    required
                    type="text"
                    tabIndex="1"
                    onFocus={this.handleFocus}
                    onChange={this.handleChange}
                  />
                  {this.errorsFor("email")}
                  {this.state.exists ? (
                    <div className="info info-error">
                      <p>{this.state.nameError}</p>
                    </div>
                  ) : null}
                </li>
              </ul>
            </form>
            <div className="dialog-actions rename-actions">
              <a
                onClick={this.handleClickCancel}
                className="btn default dialog-btn rename-cancel-btn"
              >
                {I18n.t(`rename.cancel`)}
              </a>
              <a
                onClick={this.handleClickRename}
                className="ob-btn ob-btn-compact btn-centered"
              >
                <span>{I18n.t("rename.confirm")}</span>
              </a>
            </div>
            {this.state.isLoading ? (
              <Loading>
                <code>{I18n.t(`dialog_login.loading`)}</code>
              </Loading>
            ) : null}
          </div>
        </div>
        <input type="hidden" id="nametext" value="" />
        <button
          id="btnChangeName"
          className="hidden"
          onClick={this.handleChangeName}
        ></button>
      </div>
    );
  }
}
