import React, { useCallback, useRef, useState } from 'react'
import { I18n } from 'react-i18nify-lite'
import logomono from '../images/branding/prey-logo-monotono-alt.svg'
import { Loading } from '../assets/Dialog'

const ActionLink = ({ className, onClick, href = '#', children, ...rest }) => (
  <a className={className} href={href} onClick={onClick} {...rest}>
    {children}
  </a>
)

const PasswordVisibilityIcon = ({ visible }) => (
  <svg
    viewBox="0 0 24 24"
    aria-hidden="true"
    focusable="false"
    className="login-password-toggle-icon"
  >
    <path
      d="M2.25 12s3.75-6 9.75-6 9.75 6 9.75 6-3.75 6-9.75 6-9.75-6-9.75-6Z"
      fill="none"
      stroke="currentColor"
      strokeWidth="1.8"
      strokeLinecap="round"
      strokeLinejoin="round"
    />
    <circle
      cx="12"
      cy="12"
      r="3"
      fill="none"
      stroke="currentColor"
      strokeWidth="1.8"
    />
    {visible ? (
      <path
        d="M4.5 19.5 19.5 4.5"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.8"
        strokeLinecap="round"
      />
    ) : null}
  </svg>
)

const CommonLogin = ({
  passwordType = 'password',
  onFocus,
  onPasswordFocus,
  onTogglePassword,
  onSubmit,
  onQr,
  onCreateAccount,
  createAccountHref = '#',
  onForgot,
  forgotHref = '#',
  onTerms,
  termsHref = '#',
  onPrivacy,
  privacyHref = '#',
  cookiesHref = 'https://www.preyproject.com/privacy#cookies',
  emailError,
  passwordError,
  passwordNotice,
  keyboardBridge,
  isLoading = false,
}) => {
  const [activeTab, setActiveTab] = useState('email')
  const [capsLockOn, setCapsLockOn] = useState(false)
  const capsPollTimeout = useRef(null)

  const clearCapsPoll = useCallback(() => {
    if (capsPollTimeout.current) {
      clearTimeout(capsPollTimeout.current)
      capsPollTimeout.current = null
    }
  }, [])

  const syncCapsLock = useCallback((event) => {
    let capsLockValue = null

    if (event && typeof event.getModifierState === 'function') {
      capsLockValue = event.getModifierState('CapsLock')
    }

    if (capsLockValue === null && keyboardBridge && typeof keyboardBridge.getCapsLockState === 'function') {
      capsLockValue = keyboardBridge.getCapsLockState()
    }

    if (typeof capsLockValue === 'boolean') {
      setCapsLockOn(capsLockValue)
    }
  }, [keyboardBridge])

  const scheduleCapsLockSync = useCallback((remainingPolls) => {
    if (!remainingPolls || remainingPolls <= 0) {
      clearCapsPoll()
      return
    }

    clearCapsPoll()
    capsPollTimeout.current = setTimeout(() => {
      syncCapsLock()
      scheduleCapsLockSync(remainingPolls - 1)
    }, 1000)
  }, [clearCapsPoll, syncCapsLock])

  const handlePasswordInteraction = useCallback((event) => {
    if (keyboardBridge && typeof keyboardBridge.touch === 'function') {
      keyboardBridge.touch()
      setCapsLockOn(false)
      scheduleCapsLockSync(keyboardBridge.pollCount || 1)
    }

    syncCapsLock(event)
  }, [keyboardBridge, scheduleCapsLockSync, syncCapsLock])

  const handleFormFocus = useCallback((event) => {
    if (onFocus) {
      onFocus(event)
    }

    if (event.target && event.target.id === 'passlogin') {
      syncCapsLock(event.nativeEvent || event)
    }
  }, [onFocus, syncCapsLock])

  return (
    <div className="login fs-onboarding regular inverted login-redesign">
      <div className="column">
        <div className="login-brand">
          <img src={logomono} alt="Prey" className="login-brand-logo" />
        </div>

        <div className="sign-form login-panel login-card">
          <div className="login-tabs" role="tablist" aria-label="Login methods">
            <button
              type="button"
              className={`login-tab${activeTab === 'email' ? ' active' : ''}`}
              onClick={() => setActiveTab('email')}
            >
              {I18n.t('signin.tab_email')}
            </button>
            <button
              type="button"
              className={`login-tab${activeTab === 'qr' ? ' active' : ''}`}
              onClick={() => setActiveTab('qr')}
            >
              {I18n.t('signin.tab_qr')}
            </button>
          </div>

          <div className="login-card-body">
            {activeTab === 'email' ? (
              <form autoComplete="off" className="form form-session login-pane" id="new-session" acceptCharset="UTF-8" onFocus={handleFormFocus}>
                <div className="login-pane-header">
                  <p className="login-pane-copy">{I18n.t('signin.email_copy')}</p>
                </div>

                <div className="login-pane-main">
                  <ul className="form vvv">
                    <li>
                      <label htmlFor="emaillogin">{I18n.t('signin.field1')}</label>
                      <input id="emaillogin" name="email" placeholder=" " required type="email" tabIndex="1" onFocus={onFocus} />
                      {emailError}
                    </li>
                  </ul>

                  <ul className="form hvv">
                    <li className="superpassword">
                      <label className="tag-label" htmlFor="passlogin">
                        {I18n.t('signin.field2')}
                        <div className="login-password-field">
                          <input
                            type={passwordType}
                            name="password1"
                            id="passlogin"
                            tabIndex="2"
                            onFocus={handleFormFocus}
                            onClick={handlePasswordInteraction}
                            onKeyDown={(event) => syncCapsLock(event.nativeEvent || event)}
                            onKeyUp={(event) => syncCapsLock(event.nativeEvent || event)}
                          />
                          <button
                            type="button"
                            className={`login-password-toggle${passwordType === 'text' ? ' is-active' : ''}`}
                            onClick={onTogglePassword}
                            aria-label={passwordType === 'text' ? 'Hide password' : 'Show password'}
                          >
                            <PasswordVisibilityIcon visible={passwordType === 'text'} />
                          </button>
                        </div>
                      </label>
                    {capsLockOn ? (
                      <div className="info info-warning"><p>{I18n.t('signup.capsLockIsOn')}</p></div>
                    ) : null}
                    {passwordNotice}
                    {passwordError}
                  </li>
                  </ul>

                  <button
                    type="button"
                    tabIndex="3"
                    onClick={onSubmit}
                    className="ob-btn login-submit-btn"
                  >
                    {I18n.t('signin.button_submit')}
                  </button>
                </div>
              </form>
            ) : (
              <div className="login-qr-panel login-pane">
                <div className="login-pane-header">
                  <p className="login-pane-copy">{I18n.t('signin.qr_copy')}</p>
                </div>

                <div className="login-pane-main login-pane-main-qr">
                  <div className="login-qr-stage">
                    <button type="button" className="login-qr-code" onClick={onQr} aria-label={I18n.t('signin.button_qr')}>
                      <span className="finder finder-tl" />
                      <span className="finder finder-tr" />
                      <span className="finder finder-bl" />
                      <span className="scan-line" />
                    </button>
                  </div>
                  <button type="button" className="ob-btn ob-btn-compact btn-centered" onClick={onQr}>
                    {I18n.t('signin.button_qr')}
                  </button>
                </div>
              </div>
            )}
          </div>

          <div className="login-secondary-links">
            <ActionLink className="btn-link btn-block" href={createAccountHref} onClick={onCreateAccount}>
              {I18n.t('button_create_account')}
            </ActionLink>

            <ActionLink className="btn-link btn-block" href={forgotHref} onClick={onForgot}>
              {I18n.t('button_forgot')}
            </ActionLink>
          </div>

          {isLoading ? (
            <Loading><code>{I18n.t('dialog_login.loading')}</code></Loading>
          ) : null}
        </div>

        <div id="footer" className="login-footer-inline">
          <footer className="copy">
            <div className="footer-links footer-links-inline">
              <ActionLink href={termsHref} onClick={onTerms} rel="noopener noreferrer" target={onTerms ? undefined : '_blank'}>
                {I18n.t('button_terms')}
              </ActionLink>
              <ActionLink href={privacyHref} onClick={onPrivacy} rel="noopener noreferrer" target={onPrivacy ? undefined : '_blank'}>
                {I18n.t('button_privacy')}
              </ActionLink>
              <a href={cookiesHref} target="_blank" rel="noopener noreferrer">{I18n.t('button_cookies')}</a>
            </div>
          </footer>
        </div>
      </div>
    </div>
  )
}

export default CommonLogin
