import React from "react";
import preyLogo from "../images/branding/prey-logo-monotono-alt.svg";
import { Link } from "react-router-dom";

import { I18n } from "react-i18nify-lite";

// Your Security Hub
import sh1 from "../images/onboarding/ilust/1_security-hub-01.png";
import sh2 from "../images/onboarding/ilust/1_security-hub-02.png";
import sh3 from "../images/onboarding/ilust/1_security-hub-03.png";
import sh4 from "../images/onboarding/ilust/1_security-hub-04.png";
import sh5 from "../images/onboarding/ilust/1_security-hub-05.png";
import sh6 from "../images/onboarding/ilust/1_security-hub-06.png";
import sh7 from "../images/onboarding/ilust/1_security-hub-07.png";
// Track & Find
import tf1 from "../images/onboarding/ilust/02-Track-Find.png";
// React & Protect
import rp1 from "../images/onboarding/ilust/03-React-Protect.png";
// Recover with evidence
import re1 from "../images/onboarding/ilust/04-Evidencev.png";

const slides = [
  {
    headKey: "onboarding.first.head",
    bodyKey: "onboarding.first.body",
    figureClass: "secHub",
    images: [
      { src: sh1, className: "first" },
      { src: sh2, className: "second" },
      { src: sh3, className: "third" },
      { src: sh4, className: "fourth" },
      { src: sh5, className: "fifth" },
      { src: sh6, className: "sixth" },
      { src: sh7, className: "seventh" },
    ],
  },
  {
    headKey: "onboarding.second.head",
    bodyKey: "onboarding.second.body",
    figureClass: "trkFnd",
    images: [{ src: tf1, className: "first" }],
  },
  {
    headKey: "onboarding.third.head",
    bodyKey: "onboarding.third.body",
    figureClass: "",
    images: [{ src: rp1, className: "first" }],
  },
  {
    headKey: "onboarding.fourth.head",
    bodyKey: "onboarding.fourth.body",
    figureClass: "",
    images: [{ src: re1, className: "first" }],
  },
  {
    headKey: "onboarding.fifth.head",
    bodyKey: "onboarding.fifth.body",
    figureClass: "",
    images: [{ src: re1, className: "first" }],
  },
];

class OnBoarding extends React.Component {
  constructor(props) {
    super(props);
    this.state = { currentSlide: 0 };
    this.touchStartX = 0;
  }

  handleStart = (x) => {
    this.touchStartX = x;
  };

  handleEnd = (x) => {
    const diff = this.touchStartX - x;
    const { currentSlide } = this.state;
    if (diff > 50 && currentSlide < slides.length - 1) {
      this.setState({ currentSlide: currentSlide + 1 });
    } else if (diff < -50 && currentSlide > 0) {
      this.setState({ currentSlide: currentSlide - 1 });
    }
  };

  handleTouchStart = (e) => this.handleStart(e.touches[0].clientX);
  handleTouchEnd = (e) => this.handleEnd(e.changedTouches[0].clientX);
  handleMouseDown = (e) => {
    this.dragging = true;
    this.handleStart(e.clientX);
  };
  handleMouseUp = (e) => {
    if (this.dragging) {
      this.dragging = false;
      this.handleEnd(e.clientX);
    }
  };

  render() {
    const { currentSlide } = this.state;
    const current = slides[currentSlide];
    return (
      <div
        className="ob-screen"
        onTouchStart={this.handleTouchStart}
        onTouchEnd={this.handleTouchEnd}
        onMouseDown={this.handleMouseDown}
        onMouseUp={this.handleMouseUp}
      >
        <div className="ob-header">
          <img src={preyLogo} alt="Prey" className="ob-logo" />
          <Link to={`/${I18n._locale}/permissions`} className="ob-skip">
            {I18n.t("onboarding.skip")}
          </Link>
        </div>
        <div className="ob-dots">
          {slides.map((_, i) => (
            <span
              key={i}
              className={`ob-dot${i === currentSlide ? " active" : ""}`}
              onClick={() => this.setState({ currentSlide: i })}
            />
          ))}
        </div>
        <div className="ob-illustration">
          <figure
            className={`ob-figure ${current.figureClass}`}
            key={currentSlide}
          >
            <div className="bg" />
            {current.images.map((img, j) => (
              <img key={j} src={img.src} className={img.className} alt="" />
            ))}
          </figure>
        </div>
        <div className="ob-card">
          <h4 className="ob-title">{I18n.t(current.headKey)}</h4>
          <p className="ob-subtitle">{I18n.t(current.bodyKey)}</p>
          {currentSlide === 0 ? (
            <button
              className="ob-btn"
              onClick={() => this.setState({ currentSlide: currentSlide + 1 })}
            >
              {I18n.t("onboarding.start")}
            </button>
          ) : currentSlide < slides.length - 1 ? (
            <button
              className="ob-btn"
              onClick={() => this.setState({ currentSlide: currentSlide + 1 })}
            >
              {I18n.t("onboarding.continue")}
            </button>
          ) : (
            <button
              className="ob-btn"
              onClick={() => this.props.history.push(`/${I18n._locale}/permissions`)}
            >
              {I18n.t("onboarding.continue")}
            </button>
          )}
        </div>
      </div>
    );
  }
}

export default OnBoarding;
