import React, { Component } from 'react'
import { I18n } from 'react-i18nify-lite'
import { Dialog, Loading } from '../assets/Dialog'
import { motion } from 'framer-motion'
import { Group, Space, Layout } from '../assets/stash'
import { sendMessageToIos } from './commons'

const initName = () => {
  sendMessageToIos("namedevice", {openPanelWeb: true});
  return ""
}

