import React, { createRef, useEffect, useState } from "react";
import styled from "styled-components";
import { motion } from "framer-motion";

export const variantsLayout = {
  initial: {
    opacity: 0
  },
  enter: {
    opacity: 1
  },
  exit: {
    opacity: 0
  }
};

const InnerStyle = props => {
  return `
   position: relative;
   ${
     props.gridTemplate
       ? "grid-template-areas: " + props.gridTemplate + ";"
       : ""
   }
   ${props.areaName ? props.areaName : ""}
  `;
};

export const Block = styled.section`
  grid-area: ${props => props.areaName || "absolute"};
  min-width: 320px;
`;

export const LayoutStyle = props => {
  return `
    .layout {
      ${InnerStyle(props)}
    }`;
};

const LayoutSection = styled(motion.section)`
  ${props => {
    const { theme, gridTemplate, scrollableFix } = props;
    return InnerStyle({ theme, gridTemplate, scrollableFix });
  }}
`;

export function useScreenDimensions(): number {
  const [width, setWidth] = useState(window.innerWidth);
  const [height, setHeight] = useState(window.innerHeight);

  useEffect(() => {
    const handler = (event: any) => {
      setWidth(event.target.innerWidth);
      setHeight(event.target.innerHeight);
    };

    window.addEventListener("resize", handler);

    return () => {
      window.removeEventListener("resize", handler);
    };
  }, []);

  return {
    width: width,
    height: height
  };
}

export class Layout extends React.Component {
  layoutRef = createRef();
  render() {
    return (
      <LayoutSection
        {...this.props}
        ref={this.layoutRef}
        initial="initial"
        animate="enter"
        exit="exit"
        variants={variantsLayout}
      >
        {this.props.children}
      </LayoutSection>
    );
  }
}

export const withDimensionsHOC = (Component: any) => {
  return (props: any) => {
    return <Component dimensions={useScreenDimensions()} {...props} />;
  };
};
